package com.chaobo.scm.supplier.interfaces.web;

import com.chaobo.scm.common.api.*;import com.chaobo.scm.supplier.application.profile.*;import jakarta.servlet.http.HttpServletRequest;import org.springframework.security.access.prepost.PreAuthorize;import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/supplier/v1/admissions") public class SupplierAdmissionQueryController {private final SupplierAdmissionQueryApplicationService service;public SupplierAdmissionQueryController(SupplierAdmissionQueryApplicationService service){this.service=service;}@GetMapping @PreAuthorize("hasAuthority('supplier:admission:view')")public ApiResponse<PageResult<SupplierAdmissionView>> page(@RequestParam(required=false)Integer status,@RequestParam(required=false)String keyword,@RequestParam(defaultValue="1")int pageNo,@RequestParam(defaultValue="20")int pageSize,HttpServletRequest request){return ApiResponse.success(service.page(status,keyword,pageNo,pageSize),request.getHeader("X-Request-Id"),request.getHeader("X-Trace-Id"));}@GetMapping("/{id}") @PreAuthorize("hasAuthority('supplier:admission:view')")public ApiResponse<SupplierAdmissionView> detail(@PathVariable long id,HttpServletRequest request){return ApiResponse.success(service.detail(id),request.getHeader("X-Request-Id"),request.getHeader("X-Trace-Id"));}}
